/**
 * E2E Test: SEO & Meta Tags
 * Verifica que as páginas públicas têm meta tags essenciais para SEO,
 * Open Graph tags para compartilhamento social, e títulos corretos.
 */

import { test, expect } from '@playwright/test';

test.describe('SEO Meta Tags', () => {
  test('Home page has title and description', async ({ page }) => {
    await page.goto('/', { waitUntil: 'domcontentloaded' });

    // Title should exist and not be empty
    const title = await page.title();
    expect(title).toBeTruthy();
    expect(title.length).toBeGreaterThan(5);

    // Meta description should exist
    const metaDescription = page.locator('meta[name="description"]');
    const count = await metaDescription.count();
    if (count > 0) {
      const content = await metaDescription.getAttribute('content');
      expect(content).toBeTruthy();
      expect(content!.length).toBeGreaterThan(10);
    }
  });

  test('Home page has Open Graph tags', async ({ page }) => {
    await page.goto('/', { waitUntil: 'domcontentloaded' });

    // OG title
    const ogTitle = page.locator('meta[property="og:title"]');
    const ogTitleCount = await ogTitle.count();
    if (ogTitleCount > 0) {
      const content = await ogTitle.getAttribute('content');
      expect(content).toBeTruthy();
    }

    // OG description
    const ogDesc = page.locator('meta[property="og:description"]');
    const ogDescCount = await ogDesc.count();
    if (ogDescCount > 0) {
      const content = await ogDesc.getAttribute('content');
      expect(content).toBeTruthy();
    }
  });

  test('Home page has viewport meta tag', async ({ page }) => {
    await page.goto('/', { waitUntil: 'domcontentloaded' });

    const viewport = page.locator('meta[name="viewport"]');
    await expect(viewport).toBeAttached();
    const content = await viewport.getAttribute('content');
    expect(content).toContain('width');
  });

  test('Login page has unique title', async ({ page }) => {
    await page.goto('/login', { waitUntil: 'domcontentloaded' });
    const title = await page.title();
    expect(title).toBeTruthy();
    expect(title.length).toBeGreaterThan(3);
  });

  test('Pricing page has unique title', async ({ page }) => {
    await page.goto('/pricing', { waitUntil: 'domcontentloaded' });
    const title = await page.title();
    expect(title).toBeTruthy();
    expect(title.length).toBeGreaterThan(3);
  });

  test('Pages have charset meta tag', async ({ page }) => {
    await page.goto('/', { waitUntil: 'domcontentloaded' });
    const charset = page.locator('meta[charset]');
    await expect(charset).toBeAttached();
  });

  test('Pages have lang attribute on html', async ({ page }) => {
    await page.goto('/', { waitUntil: 'domcontentloaded' });
    const lang = await page.locator('html').getAttribute('lang');
    expect(lang).toBeTruthy();
  });
});

test.describe('PWA Manifest', () => {
  test('manifest.json is accessible', async ({ request }) => {
    const response = await request.get('/manifest.json');
    expect(response.status()).toBe(200);
    const body = await response.json();
    expect(body.name).toBeTruthy();
    expect(body.short_name).toBeTruthy();
    expect(body.start_url).toBeTruthy();
    expect(body.icons).toBeDefined();
    expect(Array.isArray(body.icons)).toBe(true);
    expect(body.icons.length).toBeGreaterThan(0);
  });

  test('Home page links to manifest', async ({ page }) => {
    await page.goto('/', { waitUntil: 'domcontentloaded' });
    const manifestLink = page.locator('link[rel="manifest"]');
    const count = await manifestLink.count();
    if (count > 0) {
      const href = await manifestLink.getAttribute('href');
      expect(href).toContain('manifest');
    }
  });
});

test.describe('Favicon & Icons', () => {
  test('favicon is accessible', async ({ request }) => {
    const response = await request.get('/favicon.ico');
    // favicon should exist — 200 or 204
    expect(response.status()).toBeLessThan(500);
  });
});
